class Solution:
    def maximumBags(self, capacity, rocks, additionalRocks):
        import bisect
        from itertools import accumulate
        deficits = sorted(capacity[i] - rocks[i] for i in range(len(capacity)))
        prefix = list(accumulate(deficits))
        already = sum(1 for d in deficits if d == 0)
        idx = bisect.bisect_right(prefix, additionalRocks)
        return max(idx, already)

