class Solution:
    def maximumBags(self, capacity, rocks, additionalRocks):
        need = [c - r for c, r in zip(capacity, rocks)]
        need.sort()
        cnt = 0
        for d in need:
            if additionalRocks >= d:
                additionalRocks -= d
                cnt += 1
            else:
                break
        return cnt

