var maximumBags = function(capacity, rocks, additionalRocks) {
    const need = capacity.map((c, i) => c - rocks[i]);
    need.sort((a, b) => a - b);
    let cnt = 0;
    for (const d of need) {
        if (additionalRocks >= d) {
            additionalRocks -= d;
            cnt++;
        } else {
            break;
        }
    }
    return cnt;
};
